import type { StreamFn } from "@earendil-works/pi-agent-core";
import type { Message } from "@earendil-works/pi-ai";
import { type AgentSessionEvent, type ModelRegistry as ModelRegistryType, type ToolDefinition } from "@earendil-works/pi-coding-agent";
export interface ForgePersona {
    name: string;
    description: string;
    model?: string;
    tools?: string[];
    systemPrompt: string;
    filePath: string;
}
export interface UsageStats {
    input: number;
    output: number;
    cacheRead: number;
    cacheWrite: number;
    cost: number;
    contextTokens: number;
    turns: number;
}
export interface SubagentResult {
    exitCode: 0 | 1;
    messages: Message[];
    usage: UsageStats;
    stopReason?: string;
    errorMessage?: string;
    model?: string;
    provider?: string;
}
export interface RunSubagentOptions {
    persona: ForgePersona;
    task: string;
    cwd?: string;
    signal?: AbortSignal;
    /**
     * Forge root directory. When provided, FORGE_ROOT is set in the subagent's
     * process environment so that $FORGE_ROOT in workflow tool paths resolves
     * correctly. Without this, subagent bash calls to store-cli etc. will fail
     * with "Cannot find module '/tools/store-cli.cjs'".
     */
    forgeRoot?: string;
    /**
     * Per-phase model routing (Plan 16 Slice 2). When set, forge-cli calls
     * `session.agent.setModel(registry.find(provider, model))` after session
     * creation. If the model isn't in the registry, or setModel throws, the
     * phase falls through to inherit pi's current model — no crash.
     *
     * result.model / result.provider always reflect what the stream returned
     * (not this field) — IL10 emit path reads runtime telemetry, not the request.
     */
    requestedModel?: {
        provider: string;
        model: string;
    };
    /**
     * FORGE-BUG-001 followup. The host pi session's ModelRegistry — the only
     * registry that contains extension-registered providers (e.g.
     * `ollama-cloud`). When omitted, runForgeSubagent builds a fresh
     * `ModelRegistry.create(AuthStorage.create())` which only sees the
     * baseline providers wired up at process start, and every per-persona
     * `setModel` call will MISS — silently falling back to pi's current
     * model (typically Anthropic). Callers running inside an extension
     * command context MUST pass `ctx.modelRegistry` here.
     *
     * The same registry is used both for `registry.find(...)` (so the
     * routing decision sees the right providers) and as the subagent
     * session's registry (so the spawned agent can resolve the model id).
     */
    modelRegistry?: ModelRegistryType;
    onEvent?: (event: AgentSessionEvent) => void;
    /**
     * Optional tag included in the auto-exported transcript filename for
     * greppability — e.g. `${taskId}__${phaseRole}`. Stripped to a safe
     * filename slug. See forge-cli#8.
     */
    exportTag?: string;
    /**
     * Optional prompt-cache session identifier forwarded to the underlying pi
     * Agent (which forwards it to the LLM provider as a cache namespace key).
     *
     * Forge sets this to a sprint-scoped value (e.g. `forge:FORGE-S21`) so
     * that every persona spawned within a sprint shares a cache prefix on
     * Anthropic (system prompt + persona + skills + tools all stay warm) and
     * a stable `prompt_cache_key` on OpenAI. Combined with
     * `PI_CACHE_RETENTION=long` (defaulted in bin/forge.ts), this captures
     * the majority of cacheable mass across a ~10-minute phase and the gaps
     * between phases.
     *
     * When omitted, no sessionId is set and providers fall back to their
     * default cache behaviour (Anthropic: implicit prefix match within the
     * stream; OpenAI: in-memory, request-scoped).
     */
    cacheSessionId?: string;
    /**
     * Test-only seam: when set, replaces the underlying pi Agent's `streamFn`
     * after `createAgentSession`. The agent loop still executes real tool calls
     * — only the LLM provider is replaced with a scripted fake. Used by
     * `test/helpers/scripted-subagent.ts` to drive ceremony / pipeline tests
     * without mocking `forge-subagent` itself. See forge-cli#17.
     *
     * MUST be `undefined` in production code. Setting this in production code
     * would silently route a real subagent dispatch through a fake provider.
     */
    streamFn?: StreamFn;
    /**
     * Forge tool definitions to inject into the subagent session via
     * `createAgentSession({ customTools })`. When provided, the subagent can
     * call `forge_store`, `forge_store_describe`, etc. as named MCP tools
     * instead of shelling out to `store-cli.cjs` via bash.
     *
     * Use `getSubagentTools(forgeToolDefs, persona.name)` from forge-tools.ts
     * to build the appropriate subset for each persona.
     */
    customTools?: ToolDefinition[];
    /**
     * When true, suppress extension and skill discovery in the subagent session.
     * Default false — subagents inherit the parent's extensions (lean-ctx,
     * ollama-cloud, etc.) so they get the same tool surface.
     *
     * Test harnesses should set this to true to avoid loading globally-installed
     * extensions (which adds latency and creates environment-dependent behavior).
     */
    noExtensions?: boolean;
}
